<template>
  <div class="container">
    <div class="row">
      <div class="col">
        <div class="p-3">
          <p class="h1">Daily VS Team</p>
          <DatePicker color="red" title-position="left"
            is-dark show-weeknumbers="right-outside" @dayclick="onDayClick"
            :disabled-dates='{ weekdays: [1, 7] }'
            v-model="todayModel" mode='date'
            :min-date="today"
            :attributes="attrs"/>
        </div>
        <div class="p-3">
          <div class="tarjeta p-3">
            <p><b>Responsable Daily: {{daySel.person.nombre}}</b></p>
            <p><b>Backup Responsable: {{daySel.backUpSel.nombre}}</b></p>
          </div>
        </div>
        <div class="p-3" v-if="daySel.news.birthdays.length || daySel.news.holyday['nombre'] != undefined || daySel.news.events.length">
          <div class="tarjeta tarjetaRoja p-3">
            <b>Actividades y recordatorios: </b>
            <div v-if="daySel.news.birthdays.length">
              <b>Cumpleaños</b>
              <ul>
                <li v-for="birthday in daySel.news.birthdays" v-bind:key="birthday">
                  {{ birthday }}
                </li>
              </ul>
            </div>
            <div v-if="daySel.news.holyday['nombre'] != undefined">
              <b>Feriado</b>
              <ul>
                <li>
                  {{ daySel.news.holyday.nombre+ " - Irrenunciable: " +(( daySel.news.holyday.irrenunciable === '1') ? 'Si' : 'No') + ' - ' + daySel.news.holyday.tipo}}
                </li>
              </ul>
            </div>
            <div v-if="daySel.news.events.length">
              <b>Eventos:</b>
              <ul>
                <li v-for="event in daySel.news.events" v-bind:key="event">
                  {{ event }}
                </li>
              </ul>
            </div>  
          </div>
        </div> 
      </div>
    </div>
  </div>
</template>

<script>
import { DatePicker } from 'v-calendar';
import axios from 'axios';
import Colors from './json/Colors.json';
import Team from './json/Team.json';
import Events from './json/Events.json';
import moment from 'moment';
const milisegundosUpdate = 60000 * 60;

export default {
  name: 'DailyCalendar',
  components: {
    DatePicker,
  },
  data() {
    return {
      today: new Date(),
      todayModel: new Date(),
      attrs: [],
      holydayList: [],
      daySel: {
        person: {},
        backUpSel: {},
        news: {
          birthdays:[],
          holyday:{},
          events:[],
        },
      },
    };
  },
  async created() {
    this.genListAttributes();
    this.setTurn(moment(this.today).weekday(), moment(this.today).isoWeek());
    this.genBirthdayAttribute();
    await this.getHolydays(this.today.getFullYear());
    this.showNew(parseInt(moment(this.today).format('D')),
      parseInt(moment(this.today).month() +1),
      parseInt(moment(this.today).format('YYYY')));
  },
  mounted() {
    this.reloadPage();
  },
  methods: {
    onDayClick(day) {
      this.setSelected(day);
      this.showNew(day.day, day.month, day.year);
    },
    setSelected(day) {
      if(day.weekdayPosition < 6){
        this.daySel.day = day;
        this.setTurn(day.weekdayPosition, day.isoWeeknumber);
      }
    },
    genListAttributes(){
      this.attrs.push({
          key: 'today', bar: true,
          dates: this.today, fillMode: 'solid',
          contentClass: 'italic',
        });
      for (let idx = 0; idx < Events.length; idx++) {
        this.attrs.push(this.genAttribute(Events[idx]));      
      }
    },
    genAttribute(Event) {
      return {
          popover: {
            label: Event.description,
          },
          highlight: {
            start: { color: Colors[5], fillMode: 'light' },
            base: { color: Colors[5], fillMode: 'light' },
            end: { color: Colors[5], fillMode: 'outline' },
          },
          dates: {
            start: new Date(Event.start),
            end: new Date(Event.end)
          },
        };
    },
    genHolydayAttribute(holyday) {
      return {
          popover: {
            label: holyday.nombre+ " - Irrenunciable: " +(( holyday.irrenunciable === '1') ? 'Si' : 'No') + ' - ' + holyday.tipo,
          },
          highlight: {
            start: { color: 'pink', fillMode: 'light' },
            end: { color: 'pink', fillMode: 'light' }
          },
          dates: new Date(holyday.fecha+' 04:00:00'),
        };
    },
    genBirthdayAttribute(){
      for (let idx = 0; idx < Team.length; idx++) {
        if(Team[idx]['birthday'] != undefined) {
          let birthday = Team[idx].birthday.month+'-'+Team[idx].birthday.day+'-'
            +this.today.getFullYear()+' 04:00:00';
          this.attrs.push({
            dot: true,
            popover: {
              label: 'Cumpleaños: ' + Team[idx].nombre,
            },
            fillMode: 'solid',
            dates: new Date(birthday),
          });
        }      
      }
    },
    getTurnIdx(weekDay, isoWeek){
      return (weekDay + ((isoWeek -1) * 5)) % Team.length;
    },
    setTurn(weekDay, isoWeek){
      let teamIdx = this.getTurnIdx(weekDay, isoWeek);
      let bckUpIdx = (teamIdx + 2) > (Team.length -1) ? ((teamIdx + 2) % Team.length) : teamIdx + 2;
      this.daySel.person = { nombre: Team[teamIdx].nombre, email: Team[teamIdx].email};
      this.daySel.backUpSel = { nombre: Team[bckUpIdx].nombre, email: Team[bckUpIdx].email};
    },
    async getHolydays(year) {
      let response = await this.get('https://apis.digital.gob.cl/fl/feriados/'+year);
      this.holydayList = response.data;
      for (let idx = 0; idx < response.data.length; idx++) {
        this.attrs.push(this.genHolydayAttribute(response.data[idx]));      
      }
    },
    async get(_url) {
      return await axios.get(_url).then(response => { return response });
    },
    showNew(_day,_month,_year){
      let selectedDay = new Date(_year, _month -1, _day);
      let selectedDayString = _year+'-'+(_month < 10 ? '0' : '' ) + _month + '-' + (_day < 10 ? '0' : '') + _day;
      this.daySel.news.birthdays = [];
      this.daySel.news.events = [];
      this.daySel.news.holyday = {};
      for (let idx = 0; idx < Team.length; idx++) {
        if(Team[idx]['birthday'] != undefined ) {
          if(Team[idx].birthday.day == _day && Team[idx].birthday.month == _month)
          {
            this.daySel.news.birthdays.push(Team[idx].nombre);
          }
        }
      }
      for (let idx = 0; idx < Events.length; idx++) {
        if(selectedDay >= new Date(Events[idx].start) && selectedDay <= new Date(Events[idx].end)){
          this.daySel.news.events.push(Events[idx].description);
        }
      }
      for (let idx = 0; idx < this.holydayList.length; idx++) {
        if(this.holydayList[idx].fecha == selectedDayString){
          this.daySel.news.holyday = this.holydayList[idx];
        }
      }
    },
    reloadPage() {
      let inicio = parseInt(moment(this.today).format('D'));
      
      setInterval(function () {
        let ahora = parseInt(moment(new Date()).format('D'));
          if(inicio !== ahora) {
            location.reload();
          }
      }, milisegundosUpdate);
    },
  },
  watch: {
    todayModel(newValue, oldValues) {
      if(newValue === null){
        this.todayModel = oldValues;
      }
    },
  }
}
</script>

